def solve(income, expenses, investment):
    if not isinstance(income, (int, float)) or not isinstance(expenses, (int, float)) or not isinstance(investment, (int, float)):
        raise ValueError("Income, expenses, and investment must be numeric values.")

    if income < 0 or expenses < 0 or investment < 0:
        raise ValueError("Income, expenses, and investment must be non-negative.")

    profit = income - expenses
    roi = (profit / investment) * 100 if investment > 0 else 0

    return {
        "profit": profit,
        "roi": roi
    }
